SELECT AVG(CASE WHEN "strategy" = 'feeling-lucky' THEN "intrinsic_value" END) - AVG(CASE WHEN "strategy" = 'momentum' THEN "intrinsic_value" END) AS "difference" FROM (SELECT side_obj.value:"Strategy"::STRING AS "strategy", "StrikePrice" - "LastPx" AS "intrinsic_value" FROM "CYMBAL_INVESTMENTS"."CYMBAL_INVESTMENTS"."TRADE_CAPTURE_REPORT", LATERAL FLATTEN(INPUT => "Sides") side_obj WHERE side_obj.value:"Side"::STRING = 'Long' AND side_obj.value:"Strategy"::STRING IN ('feeling-lucky', 'momentum'))